arguments.argument:
if global.gamePaused=false && gDeltaDoTicks
{
  makeEnemyActive(1)
  if bActive=true and stunnedTime=0
  {
    if initDir=0 //detected
    {
      imagespeed=0.2
      detectDistX=264
      initDir=1
    }
    else if initDir=1 //coming out of ground
    {
      if image_index>=1.6
      {
        sprite_index=sMagicalLeafWalk
        image_index=0
        if x>oCharacter.x
        {
          image_xscale=-1
          xVel=-runAcc
        }
        else
        {
          image_xscale=1
          xVel=runAcc
        }
        initDir=2
      }
    }
    else if initDir=2 //normal behavior
    {
      if xVel>0
        image_xscale=1
      else
        image_xscale=-1
      
      if x>oPlayer1.x and image_xscale=1
        turnTime+=1
      else if x<oPlayer1.x and image_xscale=-1
        turnTime+=1
      if turnTime>=20
      {
        xVel*=-1
        turnTime=0
      }
      
      spinTime+=1
      if spinProg=0 //start spin
      {
        if spinTime>=spinDelay and findTargetX<224
        {
          sprite_index=sMagicalLeafSpin
          imagespeed=0.5
          xVel=0
          y-=2
          yVel=-1.5
          spinTime=0
          spinProg=1
        }
      }
      else if spinProg=1 //start movement
      {
        if spinTime>=20
        {
          imagespeed=0.2
          if x<oPlayer1.x
            xVel=runAcc*4
          else
            xVel=-runAcc*4
          yVel=0
          
          if xVel>0
            image_xscale=1
          else
            image_xscale=-1
          spinTime=0
          spinProg=0
          initDir=3
        }
      }
    }
    
    if sprite_index=sMagicalLeafSpin //spin
    {
      spinTime+=1
      if spinTime>=35
      {
        if xVel>0
          xVel=runAcc
        else
          xVel=-runAcc
        sprite_index=sMagicalLeafWalk
        image_index=0
        spinTime=0
        initDir=2
      }
    }
    
    if sprite_index!=sMagicalLeafSpin
      yVel+=0.2
    
    if isCollisionBottom(1)
      yVel=0
    if isCollisionLeft(1)
    {
      xVel=runAcc
      if initDir=3
      {
        sprite_index=sMagicalLeafWalk
        spinTime=0
        initDir=2
      }
    }
    if isCollisionRight(1)
    {
      xVel=-runAcc
      if initDir=3
      {
        sprite_index=sMagicalLeafWalk
        spinTime=0
        initDir=2
      }
    }
    moveTo(xVel,yVel)
    if isCollisionSolid()
      y-=2
    
    if y>room_height+30
      instance_destroy()
  }
  enemyStepEvent()
  image_index += imagespeed
}
